            writer.write("    <logging>\n");
            writer.write("        <level>INFO</level>\n");
            writer.write("        <file>/var/log/app.log</file>\n");
            writer.write("    </logging>\n");
            writer.write("</config>");
        }
    }

    @After
    public void tearDown() {
        // 清理临时文件
        if (tempConfigFile != null && tempConfigFile.exists()) {
            tempConfigFile.delete();
        }
